 1	import React, { Dispatch, FC, MouseEvent, SetStateAction, useState } from 'react';
 2	
 3	import SelectToggle from '@kubevirt-utils/components/toggles/SelectToggle';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { FormGroup, Select, SelectOption } from '@patternfly/react-core';
 6	
 7	import { AffinityCondition, AffinityRowData } from '../../../../utils/types';
 8	import { AFFINITY_CONDITION_LABELS } from '../../../AffinityList/utils/constants';
 9	
10	type AffinityConditionSelectProps = {
11	  focusedAffinity: AffinityRowData;
12	  setFocusedAffinity: Dispatch<SetStateAction<AffinityRowData>>;
13	};
14	
15	const AffinityConditionSelect: FC<AffinityConditionSelectProps> = ({
16	  focusedAffinity,
17	  setFocusedAffinity,
18	}) => {
19	  const { t } = useKubevirtTranslation();
20	
21	  const [isOpen, setIsOpen] = useState(false);
22	
23	  const handleChange = (event: MouseEvent<HTMLSelectElement>, value: AffinityCondition) => {
24	    event.preventDefault();
25	    setFocusedAffinity({ ...focusedAffinity, condition: value });
26	    setIsOpen(false);
27	  };
28	
29	  const onToggle = () => setIsOpen((prevIsOpen) => !prevIsOpen);
30	
31	  return (
32	    <FormGroup fieldId="condition" isRequired label={t('Condition')}>
33	      <Select
34	        toggle={SelectToggle({
35	          isExpanded: isOpen,
36	          onClick: onToggle,
37	          selected: AFFINITY_CONDITION_LABELS[focusedAffinity?.condition],
38	        })}
39	        isOpen={isOpen}
40	        onOpenChange={(open: boolean) => setIsOpen(open)}
41	        onSelect={handleChange}
42	        selected={focusedAffinity?.condition}
43	      >
44	        {Object.entries(AFFINITY_CONDITION_LABELS).map(([key, value]) => (
45	          <SelectOption key={key} value={key}>
46	            {value}
47	          </SelectOption>
48	        ))}
49	      </Select>
50	    </FormGroup>
51	  );
52	};
53	
54	export default AffinityConditionSelect;

